'use client'

import * as React from "react"
import { Slot } from "@radix-ui/react-slot"
import { motion } from 'framer-motion'
import { cva, type VariantProps } from "class-variance-authority"
import { cn } from "@/lib/utils"

const baseStyles = "inline-flex items-center justify-center whitespace-nowrap rounded-full text-sm font-medium ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50"

const flipButtonVariants = cva(baseStyles, {
  variants: {
    variant: {
      default: "",
      destructive: "",
      success: "",
      warning: "",
    },
    size: {
      default: "h-10 px-6 py-3",
      sm: "h-8 px-4 py-2 text-xs",
      lg: "h-12 px-8 py-4 text-base",
    },
  },
  defaultVariants: {
    variant: "default",
    size: "default",
  },
})

const variantStyles = {
  default: {
    primary: "bg-primary text-primary-foreground hover:bg-primary/90",
    flipped: "bg-secondary text-secondary-foreground hover:bg-secondary/90",
  },
  destructive: {
    primary: "bg-destructive text-destructive-foreground hover:bg-destructive/90",
    flipped: "bg-muted text-muted-foreground hover:bg-muted/90",
  },
  success: {
    primary: "bg-green-500 text-white hover:bg-green-500/90",
    flipped: "bg-secondary text-secondary-foreground hover:bg-secondary/90",
  },
  warning: {
    primary: "bg-yellow-500 text-white hover:bg-yellow-500/90",
    flipped: "bg-muted text-muted-foreground hover:bg-muted/90",
  },
} as const

export interface FlipButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof flipButtonVariants> {
  primaryText?: string
  secondaryText?: string
  onAction?: () => void
  asChild?: boolean
}

const FlipButton = React.forwardRef<HTMLButtonElement, FlipButtonProps>(
  ({ 
    className, 
    variant = "default",
    size,
    primaryText = "Confirm",
    secondaryText = "Cancel",
    onAction,
    asChild = false,
    ...props 
  }, ref) => {
    const [isFlipped, setIsFlipped] = React.useState(false)
    const Comp = asChild ? Slot : motion.button

    const handleClick = () => {
      setIsFlipped(!isFlipped)
      if (isFlipped && onAction) {
        onAction()
      }
    }

    const currentStyles = variantStyles[variant as keyof typeof variantStyles]
    const stateStyles = isFlipped ? currentStyles.flipped : currentStyles.primary

    return (
      <Comp
        className={cn(
          flipButtonVariants({ variant, size }),
          stateStyles,
          className
        )}
        ref={ref}
        onClick={handleClick}
        animate={{
          rotateX: isFlipped ? 180 : 0,
        }}
        transition={{ duration: 0.6, type: 'spring' }}
        whileTap={{ scale: 0.95 }}
        whileHover={{ scale: 1.05 }}
        {...props}
      >
        <motion.div
          animate={{ rotateX: isFlipped ? 180 : 0 }}
          transition={{ duration: 0.6, type: 'spring' }}
        >
          {isFlipped ? secondaryText : primaryText}
        </motion.div>
      </Comp>
    )
  }
)
FlipButton.displayName = "FlipButton"

export { FlipButton, flipButtonVariants }
